<template>
    <div id="app">
        <v-app id="inspire">
            <v-stepper v-model="e6" vertical>
                <v-stepper-step :complete="e6 > 1" step="1">
                    Pilih Transaksi Produk
                </v-stepper-step>

                <v-stepper-content step="1">
                    <v-card>
                        <v-container grid-list-md mb-0>
                            <h2 class="text-md-center">Data Transaksi</h2> 
                            <v-layout row wrap style="margin:10px"> 
                                <v-flex xs6 class="text-right"> 
                                    <v-text-field 
                                        v-model="keyword"
                                        append-icon="mdi-search"
                                        label="Pencarian" 
                                        hide-details 
                                    ></v-text-field>
                                </v-flex> 
                            </v-layout> 
                            <v-data-table 
                                :headers="headers" 
                                :items="transaksi" 
                                :search="keyword" 
                                :loading="load" 
                            > 
                                <template v-slot:body="{ items }"> 
                                    <tbody> 
                                        <tr v-for="(item,index) in items" :key="index"> 
                                            <td>{{ index + 1 }}</td>
                                            <td>{{ item.id }}</td>
                                            <td>{{ item.customer.name }}</td>
                                            <td> 
                                                <v-btn 
                                                    icon 
                                                    color="indigo" 
                                                    light 
                                                    @click="editHandler(item)"
                                                > 
                                                <v-icon>mdi-plus</v-icon>
                                                </v-btn>
                                                <v-btn
                                                    icon
                                                    color="error"
                                                    light 
                                                    @click="deleteTransaksi(item.id)"
                                                > 
                                                    <v-icon>mdi-delete</v-icon>
                                                </v-btn>
                                            </td> 
                                        </tr> 
                                    </tbody> 
                                </template> 
                            </v-data-table>
                        </v-container> 
                    </v-card>
                    <v-alert type="success" v-if="alert === true"> Berhasil </v-alert>
                    <v-btn color="primary" @click="setForm()">Continue</v-btn>
                </v-stepper-content>

                <v-stepper-step :complete="e6 > 2" step="2">Pembayaran</v-stepper-step>

                <v-stepper-content step="2">
                    <v-data-table class="my"
                        :headers="headersProTable"
                        :items="productTransactionDetails"
                        :loading="load" 
                    >
                        <template v-slot:body="{ items }"> 
                            <tbody> 
                                <tr v-for="(item,index) in items" :key="index"> 
                                    <td>{{ index + 1 }}</td>
                                    <td>{{ item.product.productName }}</td>
                                    <td>{{ item.itemQty }}</td>
                                    <td>{{ item.product.productPrice }}</td>
                                    <td>{{ item.product.meassurement }}</td>
                                    <td>{{ subTotal[index] }}</td>
                                    <td>
                                        <v-btn 
                                            icon 
                                            color="indigo" 
                                            light 
                                            @click="editTabel(item,index)"
                                        > 
                                            <v-icon>mdi-pencil</v-icon>
                                        </v-btn>
                                        <v-btn
                                                icon
                                                color="error"
                                                light 
                                                @click="deleteTabel(item,index)"
                                            > 
                                            <v-icon>mdi-delete</v-icon>
                                        </v-btn> 
                                    </td>
                                </tr> 
                            </tbody> 
                        </template>
                    </v-data-table>
                    <v-dialog v-model="dialogTab" persistent max-width="600px"> 
                        <v-card> 
                            <v-card-title> 
                                <span class="headline">Jumlah Produk</span> 
                            </v-card-title> 
                            <v-card-text> 
                                <v-form ref="formBayar">
                                <v-container> 
                                    <v-row>
                                        <v-col cols="12"> 
                                            <v-text-field label="*Jumlah Produk" v-model="formBayar.qty" :rules="[() => !!formBayar.qty.match(/^[0-9]*$/) && !!formBayar.qty || 'Jumlah harus angka 1-9 dan tidak boleh kosong']" required></v-text-field>
                                        </v-col> 
                                    </v-row> 
                                </v-container>
                                </v-form>
                            </v-card-text> 
                            <v-card-actions> 
                                <v-spacer></v-spacer> 
                                <v-btn color="blue darken-1" text @click="closeForm()">Batal</v-btn> 
                                <v-btn color="blue darken-1" text @click="setForm()">Simpan</v-btn> 
                            </v-card-actions> 
                        </v-card> 
                    </v-dialog>
                    <v-container> 
                        <v-row>
                            <v-col cols="5"> 
                                Total Biaya : {{total}}
                            </v-col>
                        </v-row>
                        <v-row v-if="dis === true">
                            <v-col cols="5"> 
                                Diskon : 
                                <v-text-field v-model="formBayar.diskon"></v-text-field>
                            </v-col>
                        </v-row>
                        <v-row>
                            <v-col cols="5"> 
                                Pembayaran : 
                                <v-text-field v-model="formBayar.pembayaran"></v-text-field>
                            </v-col>
                        </v-row>
                        <v-row>
                            <v-col cols="5"> 
                                Kembalian : {{kembalian}}
                            </v-col>
                            <v-col cols="5"> 
                                 <v-btn color="blue darken-1" text @click="setHitung()">Hitung</v-btn>
                            </v-col>
                        </v-row>
                    </v-container>
                    <v-snackbar 
                        v-model="snackbar"
                        :color="color" 
                        :multi-line="true" 
                        :timeout="3000"
                    > 
                        {{ text }} 
                        <v-btn 
                            dark 
                            text 
                            @click="snackbar = false" 
                        > 
                            Close 
                        </v-btn> 
                    </v-snackbar>
                    <v-snackbar
                        v-model="snackbarCal"
                        :color="colorCal" 
                        :multi-line="true" 
                        :timeout="3000"
                    >
                        {{textCal}}
                        <v-btn 
                            dark 
                            text 
                            @click="snackbarCal = false" 
                        > 
                            Close 
                        </v-btn> 
                    </v-snackbar>
                    <v-btn color="primary" v-if="clear === true" @click="setKonfirm()">Continue</v-btn>
                    <v-btn text @click="backConfirm()">Cancel</v-btn>
                </v-stepper-content>
            </v-stepper>
        </v-app>
    </div>
</template>
<script>
import jspdf from 'jspdf'
import 'jspdf-autotable'
export default {
    data(){
        return{
            e6 : 1,
            keyword: '',
            load: false,
            dis : false,
            alert : false,
            snackbar : false,
            color : null,
            text : '',
            snackbarCal : false,
            colorCal : null,
            textCal : '',
            typeInput : '',
            snackbar2 : false,
            color2 : null,
            text2 : '',
            clear:false,

            // Transaksi Produk
            transaksi : [],
            headers:[
                { 
                    text: 'No', 
                    value: 'no', 
                },
                { 
                    text: 'Id Transaksi', 
                    value: 'id', 
                },
                { 
                    text: 'Customer', 
                    value: 'customer_name',
                },
                {
                    text: 'Aksi',
                    value: null
                }
            ],

            // Konfirmasi
            headersProTable: [
                {
                    text: 'No', 
                    value: 'no', 
                },
                { 
                    text: 'Nama Produk', 
                    value: 'productName' 
                },
                { 
                    text: 'Jumlah Produk', 
                    value: 'productQuantity' 
                },
                { 
                    text: 'Harga Produk', 
                    value: 'productPrice' 
                },
                { 
                    text: 'Satuan Produk', 
                    value: 'meassurement' 
                },
                { 
                    text: 'Sub Total', 
                    value: 'subTotal' 
                },
                {
                    text: 'Aksi',
                    value: null
                }

            ],
            formBayar:{
                diskon: 0,
                pembayaran: 0,
                kembalian: 0,
                qty: '',
                index: '',
                id: '',

            },
            dialogTab: false,
            total: 0,
            customer:{},
            subTotal: [],
            productTransactionDetails: [],
            kembalian: 0,
            a: 0,
            transaction_id: '',
            TotalFinish: 0,
        }
    },
    methods: {
        getDataTransaksi(){
            var uri = this.$apiUrl + 'producttransaction/kasir/getall' 
            this.$http.get(uri).then(response =>{ 
                this.transaksi=response.data.data
            })
        },
        updateDataTransaksi(){
            let update = {
                id : this.formBayar.id,
                Products_id : this.formBayar.product_id,
                itemQty : this.formBayar.qty,
                updatedBy : this.$store.getters.loggedInEmployee
            }

            var uri =this.$apiUrl + 'producttransaction/kasir/updatedetailbyid' 
            this.$http.put(uri,this.$qs.stringify(update), {headers: {
            'content-type': 'application/x-www-form-urlencoded;charset=utf-8'
            }}).then(response =>{ 
                    this.snackbar = true; //mengaktifkan snackbar 
                    this.color = 'green'; //memberi warna snackbar 
                    this.text = response.data.message; //memasukkan pesan ke snackbar 
                    this.load = false; 
                    this.dialog = false;
                    this.resetForm();
                }).catch(error =>{ 
                    this.errors = error 
                    this.snackbar = true; 
                    this.text = 'Try Again'; 
                    this.color = 'red'; 
                    this.load = false; 
                })
        },
        setKonfirm(){
            this.printPDF();

            let confirm = {
                id : this.transaction_id,
                total : this.TotalFinish,
                updatedBy : this.$store.getters.loggedInEmployee
            }

            var uri =this.$apiUrl + 'producttransaction/kasir/confirm' 
            this.$http.put(uri,this.$qs.stringify(confirm), {headers: {
            'content-type': 'application/x-www-form-urlencoded;charset=utf-8'
            }}).then(response =>{ 
                    this.snackbar2 = true; //mengaktifkan snackbar 
                    this.color2 = 'green'; //memberi warna snackbar 
                    this.text2 = response.data.message; //memasukkan pesan ke snackbar 
                    this.load = false; 
                    this.dialog = false;
                    this.total = 0
                    this.formBayar.diskon = 0
                    this.formBayar.pembayaran = 0
                    this.kembalian = 0
                    this.productTransactionDetails = [];
                    this.typeInput = '';
                    this.subTotal = [];
                    this.total = 0;
                    this.clear = false
                    this.resetForm();
                }).catch(error =>{ 
                    this.errors = error 
                    this.snackbar2 = true; 
                    this.text2 = 'Try Again'; 
                    this.color2 = 'red'; 
                    this.load = false; 
                })

            this.getDataTransaksi();
            this.productTransactionDetails = [];
            this.e6 = 1;
        },
        deleteTransaksi(deleteId){
            var uri = this.$apiUrl + 'producttransaction/kasir/deletetransactionbyid/' + deleteId + '/' + this.$store.getters.loggedInEmployee
            this.$http.delete(uri).then(response =>{ 
                this.snackbar = true; 
                this.text = response.data.message; 
                this.color = 'green' 
                this.deleteDialog = false; 
                this.getDataTransaksi(); 
            }).catch(error =>{ 
                this.errors = error 
                this.snackbar = true; 
                this.text = 'Try Again'; 
                this.color = 'red'; 
            }) 
        },
        backConfirm(){
            this.productTransactionDetails = [];
            this.typeInput = '';
            this.subTotal = [];
            this.total = 0;
            this.e6 = 1;
        },
        editHandler(item){
            this.typeInput = 'new';
            this.customer = item.customer;
            this.id = item.Customers_id;
            this.productTransactionDetails = item.productTransactionDetails;
            this.transaction_id = item.id
            this.alert = true;
            console.log(this.customer)
            console.log(this.id)
            console.log(this.productTransactionDetails)
            console.log(this.transaction_id)
        },
        setSubTotal(){
            for(let i = 0; i<this.productTransactionDetails.length ; i++){
                this.subTotal[i] = parseInt(this.productTransactionDetails[i].itemQty) * parseInt(this.productTransactionDetails[i].product.productPrice)
            }
            return this.subTotal  
        },
        setTotal(){
            let temp = 0;
            for(let i = 0 ; i<this.subTotal.length ; i++){
                temp = parseInt(temp) + parseInt(this.subTotal[i])
            }
            this.total = temp;
        },
        setHitung(){
            let pemdis = (parseInt(this.formBayar.pembayaran) + parseInt(this.formBayar.diskon))

            if(parseInt(pemdis) < parseInt(this.total)){
                this.snackbarCal = true;
                this.colorCal = 'red';
                this.textCal = 'Jumlah Uang Kurang'
            }else{
                this.kembalian = 
                parseInt(pemdis) - parseInt(this.total)
                this.snackbarCal = true;
                this.colorCal = 'green';
                this.textCal = 'Berhasil, Terimakasih'
                this.clear = true
            }
        },
        setTabel(){
            if(this.id === null){
                this.dis = false
            }else{
                this.dis = true
            }
            
            this.setSubTotal();
            this.setTotal()
            this.$set(this.subTotal)
            this.alert = false
            this.e6 = 2;
        },
        editTabel(item,index){
            this.typeInput = 'update';
            this.dialogTab = true;
            this.formBayar.qty = '';
            this.formBayar.index = index;
            this.formBayar.id = item.id;
            this.formBayar.product_id = item.product.id;
        },
        setEditTabel(){
            let edit = {
                itemQty: this.formBayar.qty,
            }
            Object.assign(this.productTransactionDetails[this.formBayar.index], edit)

            this.setSubTotal();
            this.setTotal();
            this.updateDataTransaksi();
            this.closeForm();
        },
        deleteTabel(item,index){
            this.productTransactionDetails.splice(index,1)
            this.subTotal = [];
            this.setSubTotal();
            this.setTotal();
            var uri = this.$apiUrl + 'producttransaction/kasir/deletedetailbyid/' + item.id + '/' + this.$store.getters.loggedInEmployee
            this.$http.delete(uri).then(response =>{ 
                this.snackbar = true; 
                this.text = response.data.message; 
                this.color = 'green' 
                this.deleteDialog = false;
            }).catch(error =>{ 
                this.errors = error 
                this.snackbar = true; 
                this.text = 'Try Again'; 
                this.color = 'red'; 
            }) 
        },
        setForm(){
            if(this.typeInput === 'new'){
                this.setTabel()
            }else{
                this.setEditTabel()
            }
        },
        closeForm() {
            this.resetForm()
            this.dialogTab = false
        },
        resetForm(){ 
            this.$refs.formBayar.reset()
        },
        no(){
            for(let i = 0 ; i < this.productTransactionDetails.length ; i++)
            {
                this.a = this.a + (i+1);
                return this.a
            }
        },
        printPDF(){
            let i = 0;
            var doc = new jspdf("a6")
            var bulan = ['Januari','Febuari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember']
            var day = new Date().getDate()
            var months = new Date().getMonth()
            var month = bulan[months]
            var year = new Date().getFullYear()
            var hour = new Date().getHours()
            var minute = new Date().getUTCMinutes()
            var col = ["No", "Nama Produk", "Harga", "Jumlah","Harga"];
            var row = [];
            var id
            var nama
            var telepon
            var cs
            var kasir = this.$store.getters.employeeName
            var sub = 0
            var diskon
            var tempdis = this.formBayar.diskon
            var temptotal = this.total
            var total
            var x
            
            console.log(kasir)
            
            this.productTransactionDetails.forEach(element => {
                var temp = [this.no(), element.product.productName, element.product.productPrice, element.itemQty, this.subTotal[i++]];
                row.push(temp);
            });

            this.transaksi.forEach(element => {
                if(element.id === this.transaction_id){
                    id = element.id
                    nama = element.customer.name
                    telepon = element.customer.phoneNumber
                    cs = element.cs_name
                }
            });

            this.subTotal.forEach(element => {
                sub = parseInt(sub) + parseInt(element)
            });

            diskon = JSON.stringify(parseInt(this.formBayar.diskon))
            total = JSON.stringify(parseInt(temptotal) - parseInt(tempdis))
            x = JSON.stringify(id)

            this.TotalFinish = total

            var width = doc.internal.pageSize.getWidth();

            //img BASE64
                var img = 'data:image/png;base64,'


            doc.addImage(img,'PNG',0,0, width, 65)

            doc.setFont("times");
            doc.setFontSize(12);
            doc.text(140,85,'Tanggal : '+day+' - '+month+' - '+year+' '+ ''+ hour + ' : ' + minute + '');
            doc.text(20,95,id);
            doc.text(20,110,'Nama : '+nama+' ');
            doc.text(20,115,'Telepon : '+telepon+' ');
            doc.text(145,110,'CS : '+cs+' ');
            doc.text(145,115,'Kasir : '+kasir+' ');

            // img BASE64 produk
                var img2 = 'data:image/png;base64,'

            doc.addImage(img2,'PNG',0,120,width,25)

            doc.autoTable(col,row,{startY:150, theme:'grid'});

            let y = doc.lastAutoTable.finalY;

            doc.text(150,y+10,'Sub Total : '+sub+' ')
            doc.text(150,y+15,'Diskon    : '+diskon+' ')
            doc.text(150,y+20,'TOTAL     : '+total+' ')

            doc.save('Struk Penjualan Produk' + x + '')
        }
    },
    mounted(){ 
        this.getDataTransaksi();
    }, 
}
</script>